## 4. Next.js 15 App Router SSE Streaming

### Correct Pattern

```typescript
// app/api/agent/stream/route.ts
import { NextRequest } from 'next/server';

export const dynamic = 'force-dynamic';  // MANDATORY — prevents caching

export async function POST(req: NextRequest) {
  const body = await req.json();
  const encoder = new TextEncoder();

  const stream = new ReadableStream({
    async start(controller) {
      // ✅ ALL async work goes INSIDE start() — not before return
      try {
        for await (const chunk of myLangGraphStream(body.query)) {
          const sseMessage = `data: ${JSON.stringify(chunk)}\n\n`;
          controller.enqueue(encoder.encode(sseMessage));
        }
        controller.enqueue(encoder.encode('data: [DONE]\n\n'));
      } catch (err) {
        controller.enqueue(encoder.encode(`data: ${JSON.stringify({ error: String(err) })}\n\n`));
      } finally {
        controller.close();
      }
    },
    cancel() {
      // Called when client disconnects
    },
  });

  // ✅ Return Response IMMEDIATELY — don't await before this
  return new Response(stream, {
    headers: {
      'Content-Type': 'text/event-stream',
      'Cache-Control': 'no-cache, no-transform',
      'Connection': 'keep-alive',
      'X-Accel-Buffering': 'no',  // Disables nginx buffering (important on some hosts)
    },
  });
}
```

### Client-Side Consumption
```typescript
// Using native EventSource (GET only)
const es = new EventSource('/api/agent/stream');
es.onmessage = (e) => {
  if (e.data === '[DONE]') { es.close(); return; }
  const chunk = JSON.parse(e.data);
};

// For POST with body — use fetch + ReadableStream
const res = await fetch('/api/agent/stream', { method: 'POST', body: JSON.stringify({ query }) });
const reader = res.body!.getReader();
const decoder = new TextDecoder();
while (true) {
  const { done, value } = await reader.read();
  if (done) break;
  const text = decoder.decode(value);
  // parse SSE lines
}
```

### Vercel Free (Hobby) Tier Limits

| Constraint | Value |
|---|---|
| **Max function duration** | **300 seconds (5 min)** |
| **SSE streaming** | ✅ Supported — but must complete within 300s |
| **WebSockets** | ❌ Not supported |
| **Max payload (req/res body)** | **4.5 MB** |
| **Non-commercial use only** | Hobby plan restriction |
| **Timeout error** | `504: FUNCTION_INVOCATION_TIMEOUT` if exceeded |

> ⚠️ **Gotcha**: For long-running LangGraph agents (multi-step, multiple tool calls), 300s can be tight. Consider splitting into smaller sub-requests or using Vercel Pro (800s max) for production.

