/**
 * agent/state.ts
 *
 * Defines the AgentState that flows through the entire LangGraph pipeline.
 * All fields are typed; fields written by parallel nodes use array reducers
 * to prevent LangGraph's INVALID_CONCURRENT_GRAPH_UPDATE error.
 *
 * Architecture note: We use LangGraph's Annotation API (not a plain interface)
 * because the graph runtime needs to know how to merge concurrent state updates.
 */

import { Annotation } from "@langchain/langgraph";

// ---------------------------------------------------------------------------
// Sub-type definitions (data shapes from external APIs / LLM nodes)
// ---------------------------------------------------------------------------

export interface CompanyProfile {
  ticker: string;
  name: string;
  description: string;
  sector: string;
  industry: string;
  country: string;
  exchange: string;
  marketCap: number | null;
  website: string;
  ceo: string;
}

export interface FinancialData {
  incomeStatements: IncomeStatement[];
  keyMetrics: KeyMetrics | null;
  ratios: FinancialRatios | null;
}

export interface IncomeStatement {
  date: string;
  revenue: number | null;
  grossProfit: number | null;
  operatingIncome: number | null;
  netIncome: number | null;
  eps: number | null;
  grossProfitRatio: number | null;
  operatingIncomeRatio: number | null;
  netIncomeRatio: number | null;
}

export interface KeyMetrics {
  peRatio: number | null;
  pbRatio: number | null;
  evToEbitda: number | null;
  debtToEquity: number | null;
  currentRatio: number | null;
  returnOnEquity: number | null;
  returnOnAssets: number | null;
  freeCashFlowPerShare: number | null;
  revenuePerShare: number | null;
}

export interface FinancialRatios {
  grossProfitMargin: number | null;
  operatingProfitMargin: number | null;
  netProfitMargin: number | null;
  debtEquityRatio: number | null;
  quickRatio: number | null;
  dividendYield: number | null;
}

export interface SearchResult {
  title: string;
  url: string;
  content: string;
  score?: number;
  publishedDate?: string;
}

// Structured output types from LLM analysis nodes
export interface FundamentalsOutput {
  revenueGrowthAssessment: string;
  marginQuality: string;
  balanceSheetHealth: string;
  valuationComment: string;
  overallScore: "strong" | "adequate" | "weak" | "unavailable";
  keyNumbers: string[];
  dataLimitationNote?: string;
}

export interface SentimentOutput {
  overallTone: "positive" | "neutral" | "negative" | "mixed";
  momentumSignal: string;
  controversies: string[];
  recentDevelopments: string[];
  sentimentScore: number; // 0-100
}

export interface CompetitiveOutput {
  moatAssessment: string;
  marketPosition: string;
  keyCompetitors: string[];
  competitiveRisks: string[];
  differentiators: string[];
  moatScore: "wide" | "narrow" | "none" | "unclear";
}

export interface DecisionOutput {
  verdict: "INVEST" | "PASS";
  confidence: number; // 0-100
  oneLineRationale: string;
  fundamentalsSummary: string;
  sentimentSummary: string;
  competitiveSummary: string;
  keyRisks: string[];
  keyStrengths: string[];
  dataQualityNote?: string;
}

// ---------------------------------------------------------------------------
// AgentState — the graph's shared state object
// ---------------------------------------------------------------------------

export const AgentState = Annotation.Root({
  // Input
  companyName: Annotation<string>,

  // Resolved by resolve_ticker
  ticker: Annotation<string | null>({
    reducer: (_, b) => b,
    default: () => null,
  }),
  companyProfile: Annotation<CompanyProfile | null>({
    reducer: (_, b) => b,
    default: () => null,
  }),

  // Fetched by fetch_financials (parallel node)
  financials: Annotation<FinancialData | null>({
    reducer: (_, b) => b,
    default: () => null,
  }),
  financialsAvailable: Annotation<boolean>({
    reducer: (_, b) => b,
    default: () => false,
  }),

  // Fetched by parallel fetch nodes — array reducers for concurrent writes
  newsResults: Annotation<SearchResult[]>({
    reducer: (a, b) => [...a, ...b],
    default: () => [],
  }),
  webResearchResults: Annotation<SearchResult[]>({
    reducer: (a, b) => [...a, ...b],
    default: () => [],
  }),

  // LLM analysis outputs
  fundamentalsAnalysis: Annotation<FundamentalsOutput | null>({
    reducer: (_, b) => b,
    default: () => null,
  }),
  sentimentAnalysis: Annotation<SentimentOutput | null>({
    reducer: (_, b) => b,
    default: () => null,
  }),
  competitiveAnalysis: Annotation<CompetitiveOutput | null>({
    reducer: (_, b) => b,
    default: () => null,
  }),

  // Final decision
  decision: Annotation<DecisionOutput | null>({
    reducer: (_, b) => b,
    default: () => null,
  }),

  // Non-fatal errors accumulate across nodes — reducer concatenates
  errors: Annotation<string[]>({
    reducer: (a, b) => [...a, ...b],
    default: () => [],
  }),
});

export type AgentStateType = typeof AgentState.State;

/**
 * nodes/resolve-ticker.ts
 *
 * Node 1: Resolve a company name to a stock ticker and fetch its profile.
 *
 * Strategy:
 *   1. FMP /search endpoint (fast, structured, no LLM needed)
 *   2. If FMP search fails or returns nothing, fall back to Tavily search +
 *      a brief LLM extraction call to parse the ticker from web results.
 *
 * On success: sets ticker + companyProfile in state.
 * On failure: sets an error in state.errors and returns without crashing —
 *             the graph degrades gracefully; subsequent nodes check for null ticker.
 *
 * Why FMP first: it's deterministic and doesn't consume LLM tokens for a simple lookup.
 * Why Tavily fallback: handles cases like non-US companies, subsidiaries, or recently
 * renamed companies that FMP search might miss.
 */

import { AgentStateType, CompanyProfile } from "../state";

const FMP_BASE = "https://financialmodelingprep.com/api/v3";

// ---------------------------------------------------------------------------
// FMP search — resolve name → ticker
// ---------------------------------------------------------------------------

async function fmpSearchTicker(query: string): Promise<string | null> {
  const apiKey = process.env.FMP_API_KEY;
  if (!apiKey) throw new Error("FMP_API_KEY is not set");

  const url = `${FMP_BASE}/search?query=${encodeURIComponent(query)}&limit=5&exchange=NASDAQ,NYSE,AMEX&apikey=${apiKey}`;
  const res = await fetch(url, { next: { revalidate: 0 } });

  if (!res.ok) {
    throw new Error(`FMP search failed: ${res.status} ${res.statusText}`);
  }

  const data = (await res.json()) as Array<{
    symbol: string;
    name: string;
    exchangeShortName: string;
  }>;

  if (!Array.isArray(data) || data.length === 0) return null;

  // Return the first result — FMP orders by relevance
  return data[0].symbol;
}

// ---------------------------------------------------------------------------
// FMP profile fetch — ticker → CompanyProfile
// ---------------------------------------------------------------------------

async function fmpFetchProfile(ticker: string): Promise<CompanyProfile | null> {
  const apiKey = process.env.FMP_API_KEY;
  if (!apiKey) throw new Error("FMP_API_KEY is not set");

  const url = `${FMP_BASE}/profile/${ticker}?apikey=${apiKey}`;
  const res = await fetch(url, { next: { revalidate: 0 } });

  if (!res.ok) return null;

  const data = (await res.json()) as Array<Record<string, unknown>>;
  if (!Array.isArray(data) || data.length === 0) return null;

  const p = data[0];
  return {
    ticker: (p.symbol as string) ?? ticker,
    name: (p.companyName as string) ?? "",
    description: (p.description as string) ?? "",
    sector: (p.sector as string) ?? "",
    industry: (p.industry as string) ?? "",
    country: (p.country as string) ?? "",
    exchange: (p.exchangeShortName as string) ?? "",
    marketCap: typeof p.mktCap === "number" ? p.mktCap : null,
    website: (p.website as string) ?? "",
    ceo: (p.ceo as string) ?? "",
  };
}

// ---------------------------------------------------------------------------
// Tavily fallback — used when FMP search returns nothing
// Requires TAVILY_API_KEY env var.
// ---------------------------------------------------------------------------

async function tavilyFallbackTicker(companyName: string): Promise<string | null> {
  const { TavilySearch } = await import("@langchain/tavily");

  const tool = new TavilySearch({
    maxResults: 3,
    topic: "general",
  });

  const query = `${companyName} stock ticker symbol NYSE NASDAQ`;
  const results = await tool.invoke(query);

  // The results are a JSON string of search results
  const parsed = typeof results === "string" ? JSON.parse(results) : results;
  const content = Array.isArray(parsed)
    ? parsed.map((r: { content: string }) => r.content).join("\n")
    : String(parsed);

  // Extract ticker using a lightweight LLM call
  const { ChatOpenAI } = await import("@langchain/openai");
  const llm = new ChatOpenAI({
    model: "meta/llama-3.1-405b-instruct",
    apiKey: process.env.NVIDIA_NIM_API_KEY,
    configuration: {
      baseURL: process.env.NVIDIA_NIM_BASE_URL ?? "https://integrate.api.nvidia.com/v1",
    },
    temperature: 0,
    maxTokens: 20,
  });

  const response = await llm.invoke(
    `Extract ONLY the stock ticker symbol for "${companyName}" from the text below. ` +
      `Reply with just the ticker (e.g. "AAPL") and nothing else. ` +
      `If no clear ticker is found, reply "UNKNOWN".\n\nText:\n${content.slice(0, 2000)}`
  );

  const ticker = (response.content as string).trim().toUpperCase();
  return ticker === "UNKNOWN" || ticker.length > 6 ? null : ticker;
}

// ---------------------------------------------------------------------------
// Main node function
// ---------------------------------------------------------------------------

export async function resolveTickerNode(
  state: AgentStateType
): Promise<Partial<AgentStateType>> {
  const { companyName } = state;

  if (!companyName?.trim()) {
    return { errors: ["Company name is required"] };
  }

  // Step 1: Try FMP search
  let ticker: string | null = null;
  try {
    ticker = await fmpSearchTicker(companyName.trim());
  } catch (err) {
    // FMP search errored — proceed to fallback, log the error
    console.warn("[resolve_ticker] FMP search error:", err);
  }

  // Step 2: Tavily fallback if FMP returned nothing
  if (!ticker) {
    try {
      ticker = await tavilyFallbackTicker(companyName.trim());
    } catch (err) {
      console.warn("[resolve_ticker] Tavily fallback error:", err);
    }
  }

  if (!ticker) {
    return {
      errors: [
        `Could not resolve a stock ticker for "${companyName}". ` +
          "This may be a private company, a non-US listed company, or the name may be misspelled. " +
          "Verdikt currently supports US-listed equities on NYSE, NASDAQ, and AMEX.",
      ],
    };
  }

  // Step 3: Fetch company profile
  let profile: CompanyProfile | null = null;
  try {
    profile = await fmpFetchProfile(ticker);
  } catch (err) {
    console.warn("[resolve_ticker] Profile fetch error:", err);
    // Non-fatal — we have the ticker, proceed without full profile
  }

  return {
    ticker,
    companyProfile: profile,
  };
}

/**
 * nodes/fetch-financials.ts
 *
 * Parallel node: fetches financial data from Financial Modeling Prep (FMP).
 *
 * Uses Promise.all to fire three FMP API calls concurrently:
 *   - Income statement (3 years annual)
 *   - Key metrics (latest annual)
 *   - Financial ratios (latest annual)
 *
 * Graceful degradation: if FMP returns empty data (private company, OTC, or
 * insufficient history), sets financialsAvailable = false. The downstream
 * analyze_fundamentals node checks this flag and adjusts its analysis.
 *
 * This node runs in parallel with fetch_news and fetch_web_research.
 * It writes to ticker-specific fields (financials, financialsAvailable),
 * which are non-array fields with last-write-wins reducers — safe for parallel execution.
 */

import {
  AgentStateType,
  FinancialData,
  IncomeStatement,
  KeyMetrics,
  FinancialRatios,
} from "../state";

const FMP_BASE = "https://financialmodelingprep.com/api/v3";

// ---------------------------------------------------------------------------
// Individual fetchers
// ---------------------------------------------------------------------------

async function fetchIncomeStatements(
  ticker: string,
  apiKey: string
): Promise<IncomeStatement[]> {
  const url = `${FMP_BASE}/income-statement/${ticker}?period=annual&limit=3&apikey=${apiKey}`;
  const res = await fetch(url, { next: { revalidate: 0 } });
  if (!res.ok) return [];

  const data = (await res.json()) as Array<Record<string, unknown>>;
  if (!Array.isArray(data)) return [];

  return data.map((d) => ({
    date: (d.date as string) ?? "",
    revenue: typeof d.revenue === "number" ? d.revenue : null,
    grossProfit: typeof d.grossProfit === "number" ? d.grossProfit : null,
    operatingIncome: typeof d.operatingIncome === "number" ? d.operatingIncome : null,
    netIncome: typeof d.netIncome === "number" ? d.netIncome : null,
    eps: typeof d.eps === "number" ? d.eps : null,
    grossProfitRatio: typeof d.grossProfitRatio === "number" ? d.grossProfitRatio : null,
    operatingIncomeRatio: typeof d.operatingIncomeRatio === "number" ? d.operatingIncomeRatio : null,
    netIncomeRatio: typeof d.netIncomeRatio === "number" ? d.netIncomeRatio : null,
  }));
}

async function fetchKeyMetrics(
  ticker: string,
  apiKey: string
): Promise<KeyMetrics | null> {
  const url = `${FMP_BASE}/key-metrics/${ticker}?period=annual&limit=1&apikey=${apiKey}`;
  const res = await fetch(url, { next: { revalidate: 0 } });
  if (!res.ok) return null;

  const data = (await res.json()) as Array<Record<string, unknown>>;
  if (!Array.isArray(data) || data.length === 0) return null;

  const d = data[0];
  return {
    peRatio: typeof d.peRatio === "number" ? d.peRatio : null,
    pbRatio: typeof d.pbRatio === "number" ? d.pbRatio : null,
    evToEbitda: typeof d.evToEbitda === "number" ? d.evToEbitda : null,
    debtToEquity: typeof d.debtToEquity === "number" ? d.debtToEquity : null,
    currentRatio: typeof d.currentRatio === "number" ? d.currentRatio : null,
    returnOnEquity: typeof d.returnOnEquity === "number" ? d.returnOnEquity : null,
    returnOnAssets: typeof d.returnOnAssets === "number" ? d.returnOnAssets : null,
    freeCashFlowPerShare:
      typeof d.freeCashFlowPerShare === "number" ? d.freeCashFlowPerShare : null,
    revenuePerShare: typeof d.revenuePerShare === "number" ? d.revenuePerShare : null,
  };
}

async function fetchRatios(
  ticker: string,
  apiKey: string
): Promise<FinancialRatios | null> {
  const url = `${FMP_BASE}/ratios/${ticker}?period=annual&limit=1&apikey=${apiKey}`;
  const res = await fetch(url, { next: { revalidate: 0 } });
  if (!res.ok) return null;

  const data = (await res.json()) as Array<Record<string, unknown>>;
  if (!Array.isArray(data) || data.length === 0) return null;

  const d = data[0];
  return {
    grossProfitMargin:
      typeof d.grossProfitMargin === "number" ? d.grossProfitMargin : null,
    operatingProfitMargin:
      typeof d.operatingProfitMargin === "number" ? d.operatingProfitMargin : null,
    netProfitMargin: typeof d.netProfitMargin === "number" ? d.netProfitMargin : null,
    debtEquityRatio: typeof d.debtEquityRatio === "number" ? d.debtEquityRatio : null,
    quickRatio: typeof d.quickRatio === "number" ? d.quickRatio : null,
    dividendYield: typeof d.dividendYield === "number" ? d.dividendYield : null,
  };
}

// ---------------------------------------------------------------------------
// Main node function
// ---------------------------------------------------------------------------

export async function fetchFinancialsNode(
  state: AgentStateType
): Promise<Partial<AgentStateType>> {
  const { ticker } = state;

  // If ticker resolution failed, skip gracefully
  if (!ticker) {
    return {
      financialsAvailable: false,
      errors: ["Financials skipped — no ticker resolved"],
    };
  }

  const apiKey = process.env.FMP_API_KEY;
  if (!apiKey) {
    return {
      financialsAvailable: false,
      errors: ["FMP_API_KEY is not configured — financial data unavailable"],
    };
  }

  try {
    // Fire all three requests concurrently
    const [incomeStatements, keyMetrics, ratios] = await Promise.all([
      fetchIncomeStatements(ticker, apiKey),
      fetchKeyMetrics(ticker, apiKey),
      fetchRatios(ticker, apiKey),
    ]);

    // Consider data available if we got at least one income statement
    const financialsAvailable = incomeStatements.length > 0;

    if (!financialsAvailable) {
      return {
        financials: null,
        financialsAvailable: false,
        errors: [
          `No financial data found for ${ticker} on FMP. ` +
            "This may indicate a non-US company, a recently listed company, or insufficient data coverage.",
        ],
      };
    }

    const financials: FinancialData = {
      incomeStatements,
      keyMetrics,
      ratios,
    };

    return {
      financials,
      financialsAvailable: true,
    };
  } catch (err) {
    console.error("[fetch_financials] Error:", err);
    return {
      financials: null,
      financialsAvailable: false,
      errors: [
        `Failed to fetch financial data for ${ticker}: ${err instanceof Error ? err.message : String(err)}`,
      ],
    };
  }
}

/**
 * nodes/fetch-news.ts
 *
 * Parallel node: fetches recent news about the company using Tavily.
 *
 * Uses @langchain/tavily's TavilySearch with topic: "news" and a 1-month
 * time range to surface material recent coverage.
 *
 * This node runs in parallel with fetch_financials and fetch_web_research.
 * Results are written to state.newsResults — which uses an array concat reducer,
 * so parallel writes are safe.
 */

import { TavilySearch } from "@langchain/tavily";
import { AgentStateType, SearchResult } from "../state";

export async function fetchNewsNode(
  state: AgentStateType
): Promise<Partial<AgentStateType>> {
  const { ticker, companyProfile } = state;

  if (!ticker) {
    return { errors: ["News search skipped — no ticker resolved"] };
  }

  // Build a targeted query: use both company name and ticker for precision
  const companyName = companyProfile?.name ?? ticker;
  const query = `${companyName} ${ticker} latest news earnings analyst investment`;

  try {
    const tool = new TavilySearch({
      maxResults: 8,
      topic: "news",
      searchDepth: "advanced",
      // 1-month time range keeps results relevant; avoids stale articles
      timeRange: "month",
      includeAnswer: false,
      includeRawContent: false,
    });

    const rawResults = await tool.invoke(query);

    // TavilySearch returns a JSON string of results
    const parsed =
      typeof rawResults === "string" ? JSON.parse(rawResults) : rawResults;

    const results: SearchResult[] = Array.isArray(parsed)
      ? parsed.map((r: Record<string, unknown>) => ({
          title: (r.title as string) ?? "",
          url: (r.url as string) ?? "",
          content: (r.content as string) ?? "",
          score: typeof r.score === "number" ? r.score : undefined,
          publishedDate:
            typeof r.published_date === "string" ? r.published_date : undefined,
        }))
      : [];

    return { newsResults: results };
  } catch (err) {
    console.error("[fetch_news] Error:", err);
    return {
      newsResults: [],
      errors: [
        `News search failed: ${err instanceof Error ? err.message : String(err)}. Sentiment analysis will be limited.`,
      ],
    };
  }
}

/**
 * nodes/fetch-web-research.ts
