/**
 * nodes/synthesize-decision.ts
 *
 * LLM node: synthesizes all prior analysis into a final INVEST/PASS verdict.
 *
 * This is the most architecturally important node. Its system prompt explicitly:
 *   1. Injects the FULL structured outputs of fundamentalsAnalysis,
 *      sentimentAnalysis, and competitiveAnalysis as JSON
 *   2. Instructs the model that its verdict MUST reference specific findings
 *      from those prior outputs — it is synthesizing, not generating fresh opinion
 *   3. Prohibits introducing new information not present in the prior analysis
 *
 * The DecisionSchema's .describe() fields reinforce these constraints at the
 * field level — fundamentalsSummary "MUST reference specific numbers or scores
 * from the fundamentals node output", etc.
 *
 * This design makes the reasoning chain traceable: a reviewer can compare the
 * decision output to the analysis outputs and verify the logic holds.
 */

import { ChatOpenAI } from "@langchain/openai";
import { AgentStateType } from "../state";
import { DecisionSchema } from "../schemas";

// ---------------------------------------------------------------------------
// Main node function
// ---------------------------------------------------------------------------

export async function synthesizeDecisionNode(
  state: AgentStateType
): Promise<Partial<AgentStateType>> {
  if (!state.ticker) {
    return { errors: ["Decision synthesis skipped — no ticker resolved"] };
  }

  const llm = new ChatOpenAI({
    model: "meta/llama-3.1-405b-instruct",
    apiKey: process.env.NVIDIA_NIM_API_KEY,
    configuration: {
      baseURL: process.env.NVIDIA_NIM_BASE_URL ?? "https://integrate.api.nvidia.com/v1",
    },
    temperature: 0.2, // Slightly higher temp for synthesis — still deterministic enough
  });

  const structuredLlm = llm.withStructuredOutput(DecisionSchema, {
    method: "json_schema",
  });

  const companyName = state.companyProfile?.name ?? state.ticker;

  // Inject all prior analysis as structured JSON so the model synthesizes
  // rather than re-derives conclusions
  const priorAnalysis = JSON.stringify(
    {
      company: { name: companyName, ticker: state.ticker },
      fundamentalsAnalysis: state.fundamentalsAnalysis,
      sentimentAnalysis: state.sentimentAnalysis,
      competitiveAnalysis: state.competitiveAnalysis,
      dataFlags: {
        financialsAvailable: state.financialsAvailable,
        newsCount: state.newsResults.length,
        webResearchCount: state.webResearchResults.length,
        nonFatalErrors: state.errors,
      },
    },
    null,
    2
  );

  const systemPrompt =
    `You are the lead analyst on an investment research team. ` +
    `Your colleagues have completed three independent analyses of ${companyName} (${state.ticker}): ` +
    `fundamental analysis, sentiment analysis, and competitive analysis. ` +
    `Your task is to synthesize their findings into a final INVEST or PASS verdict.\n\n` +
    `CRITICAL RULES:\n` +
    `1. Your verdict MUST be based on the findings provided below — do not introduce new information.\n` +
    `2. Your fundamentalsSummary MUST cite specific numbers from the fundamentals analysis (e.g. actual scores, margins mentioned).\n` +
    `3. Your sentimentSummary MUST cite specific developments or controversies from the sentiment analysis.\n` +
    `4. Your competitiveSummary MUST cite the moat score and specific findings from the competitive analysis.\n` +
    `5. If data was unavailable, lower your confidence score accordingly and note it in dataQualityNote.\n` +
    `6. keyRisks and keyStrengths must be synthesized from the prior analyses — not invented.\n` +
    `7. Confidence 70+ means clear evidence. 50-69 means mixed signals. Below 50 means data is insufficient for a conviction call.`;

  const userPrompt =
    `Based on the following research findings, deliver your final investment verdict for ${companyName} (${state.ticker}).\n\n` +
    `RESEARCH FINDINGS:\n\`\`\`json\n${priorAnalysis}\n\`\`\`\n\n` +
    `Synthesize all three analyses into a final INVEST or PASS decision. ` +
    `Your reasoning must explicitly connect to what each prior analysis found.`;

  try {
    const result = await structuredLlm.invoke([
      { role: "system", content: systemPrompt },
      { role: "user", content: userPrompt },
    ]);

    return { decision: result };
  } catch (err) {
    console.error("[synthesize_decision] Error:", err);
    return {
      errors: [`Decision synthesis failed: ${err instanceof Error ? err.message : String(err)}`],
    };
  }
}

/**
 * agent/graph.ts
 *
 * Assembles the Verdikt LangGraph pipeline.
 *
 * Graph structure:
 *
 *   START
 *     → resolve_ticker
 *     → [parallel fan-out]
 *         → fetch_financials   ─┐
 *         → fetch_news          ├→ gather_data (fan-in)
 *         → fetch_web_research ─┘
 *     → analyze_fundamentals
 *     → analyze_sentiment
 *     → analyze_competitive
 *     → synthesize_decision
 *   END
 *
 * The three parallel fetch nodes run in the same LangGraph super-step,
 * executing concurrently. gather_data acts as a fan-in synchronization point
 * — LangGraph will not advance to analyze_fundamentals until all three
 * parallel nodes have completed.
 *
 * Each node writes to its own dedicated state keys with appropriate reducers,
 * preventing INVALID_CONCURRENT_GRAPH_UPDATE errors during parallel execution.
 *
 * Decision to use StateGraph vs. MessageGraph:
 * StateGraph is correct here because we're accumulating typed research findings,
 * not a conversational message history. The state schema is the source of truth
 * for what the agent has learned.
 */

import { StateGraph, START, END } from "@langchain/langgraph";
import { AgentState } from "./state";
import { resolveTickerNode } from "./nodes/resolve-ticker";
import { fetchFinancialsNode } from "./nodes/fetch-financials";
import { fetchNewsNode } from "./nodes/fetch-news";
import { fetchWebResearchNode } from "./nodes/fetch-web-research";
import { gatherDataNode } from "./nodes/gather-data";
import { analyzeFundamentalsNode } from "./nodes/analyze-fundamentals";
import { analyzeSentimentNode } from "./nodes/analyze-sentiment";
import { analyzeCompetitiveNode } from "./nodes/analyze-competitive";
import { synthesizeDecisionNode } from "./nodes/synthesize-decision";

/**
 * Builds and compiles the research graph.
 *
 * Called once per request in the API route — the compiled graph is not a
 * singleton because Next.js serverless functions are stateless. If this were
 * a long-running server, we'd memoize the compiled graph.
 */
export function buildGraph() {
  const graph = new StateGraph(AgentState)
    // -------------------------------------------------------------------------
    // Node registrations
    // -------------------------------------------------------------------------
    .addNode("resolve_ticker", resolveTickerNode)
    .addNode("fetch_financials", fetchFinancialsNode)
    .addNode("fetch_news", fetchNewsNode)
    .addNode("fetch_web_research", fetchWebResearchNode)
    .addNode("gather_data", gatherDataNode)
    .addNode("analyze_fundamentals", analyzeFundamentalsNode)
    .addNode("analyze_sentiment", analyzeSentimentNode)
    .addNode("analyze_competitive", analyzeCompetitiveNode)
    .addNode("synthesize_decision", synthesizeDecisionNode)

    // -------------------------------------------------------------------------
    // Edge definitions — these declare the execution order
    // -------------------------------------------------------------------------

    // Entry point
    .addEdge(START, "resolve_ticker")

    // Fan-out: resolve_ticker → three parallel nodes in the same super-step
    .addEdge("resolve_ticker", "fetch_financials")
    .addEdge("resolve_ticker", "fetch_news")
    .addEdge("resolve_ticker", "fetch_web_research")

    // Fan-in: all three parallel nodes → gather_data (convergence point)
    .addEdge("fetch_financials", "gather_data")
    .addEdge("fetch_news", "gather_data")
    .addEdge("fetch_web_research", "gather_data")

    // Sequential analysis chain (each builds on accumulated state)
    .addEdge("gather_data", "analyze_fundamentals")
    .addEdge("analyze_fundamentals", "analyze_sentiment")
    .addEdge("analyze_sentiment", "analyze_competitive")
    .addEdge("analyze_competitive", "synthesize_decision")

    // Terminal edge
    .addEdge("synthesize_decision", END);

  return graph.compile();
}

// Export the node name list for use in the streaming API route
// so we can map LangGraph event node names to human-readable labels
export const NODE_LABELS: Record<string, string> = {
  resolve_ticker: "Resolving ticker",
  fetch_financials: "Fetching financials",
  fetch_news: "Fetching news",
  fetch_web_research: "Researching competitive landscape",
  gather_data: "Gathering data",
  analyze_fundamentals: "Analyzing fundamentals",
  analyze_sentiment: "Analyzing sentiment",
  analyze_competitive: "Analyzing competitive position",
  synthesize_decision: "Synthesizing verdict",
};

/**
 * app/api/research/route.ts
 *
 * SSE streaming endpoint for the Verdikt research pipeline.
 *
 * Contract:
 *   POST /api/research
 *   Body: { company: string }
 *   Response: text/event-stream
 *
 * SSE message types:
 *   { type: "node_start",    node: string, label: string }
 *   { type: "node_complete", node: string, label: string, data: object }
 *   { type: "error",         message: string }
 *   { type: "done" }
 *
 * Why SSE over WebSockets: SSE is simpler (HTTP), supported on Vercel's free
 * tier, and sufficient for a unidirectional server→client stream. WebSockets
 * are not supported on Vercel serverless functions.
 *
 * Why ReadableStream + fetch (not native EventSource): native EventSource only
 * supports GET requests. Since we need to POST a body (the company name), we
 * use fetch on the client side and parse SSE lines from the ReadableStream.
 *
 * Streaming pattern: ALL async work (graph.streamEvents) goes INSIDE
 * ReadableStream's start(controller) function. Anything awaited before
 * `return new Response(stream, ...)` would be buffered by Next.js, defeating
 * the point of streaming.
 *
 * Vercel limit: 300 seconds (5 min) on Hobby tier. Set maxDuration accordingly.
 */

import { NextRequest } from "next/server";
import { buildGraph, NODE_LABELS } from "@/lib/agent/graph";

export const dynamic = "force-dynamic";
export const maxDuration = 300; // 5 minutes — Vercel Hobby tier maximum

// ---------------------------------------------------------------------------
// Input validation
// ---------------------------------------------------------------------------

function validateCompanyName(company: unknown): string | null {
  if (typeof company !== "string") return null;
  const trimmed = company.trim();
  if (trimmed.length < 1 || trimmed.length > 200) return null;
  return trimmed;
}

// ---------------------------------------------------------------------------
// POST handler
// ---------------------------------------------------------------------------

export async function POST(req: NextRequest): Promise<Response> {
  // Parse and validate request body
  let companyName: string | null = null;
  try {
    const body = await req.json();
    companyName = validateCompanyName(body?.company);
  } catch {
    return new Response(
      JSON.stringify({ error: "Invalid request body. Expected: { company: string }" }),
      { status: 400, headers: { "Content-Type": "application/json" } }
    );
  }

  if (!companyName) {
    return new Response(
      JSON.stringify({ error: "company must be a non-empty string (max 200 chars)" }),
      { status: 400, headers: { "Content-Type": "application/json" } }
    );
  }

  // Check required env vars early — surface the error clearly
  const missingEnvVars: string[] = [];
  if (!process.env.NVIDIA_NIM_API_KEY) missingEnvVars.push("NVIDIA_NIM_API_KEY");
  if (!process.env.TAVILY_API_KEY) missingEnvVars.push("TAVILY_API_KEY");
  if (!process.env.FMP_API_KEY) missingEnvVars.push("FMP_API_KEY");

  if (missingEnvVars.length > 0) {
    return new Response(
      JSON.stringify({
        error: `Missing required environment variables: ${missingEnvVars.join(", ")}. See .env.example.`,
      }),
      { status: 500, headers: { "Content-Type": "application/json" } }
    );
  }

  const encoder = new TextEncoder();

  // Track which nodes have started (for deduplication of start events)
  const startedNodes = new Set<string>();

  const stream = new ReadableStream({
    async start(controller) {
      const send = (message: object): void => {
        try {
          controller.enqueue(
            encoder.encode(`data: ${JSON.stringify(message)}\n\n`)
          );
        } catch {
          // Controller may be closed if client disconnected
        }
      };

      try {
        const graph = buildGraph();

        // streamEvents v2: emits on_chain_start / on_chain_end for each node
        // We filter by langgraph_node metadata to get per-node events
        const eventStream = graph.streamEvents(
          { companyName },
          { version: "v2" }
        );

        for await (const event of eventStream) {
          const nodeName = event.metadata?.langgraph_node as string | undefined;

          if (!nodeName || !NODE_LABELS[nodeName]) continue;

          // Emit node_start on first on_chain_start for this node
          if (event.event === "on_chain_start" && !startedNodes.has(nodeName)) {
            startedNodes.add(nodeName);
            send({
              type: "node_start",
              node: nodeName,
              label: NODE_LABELS[nodeName],
            });
          }

          // Emit node_complete with the node's output on on_chain_end
          if (event.event === "on_chain_end") {
            const output = event.data?.output;
            send({
              type: "node_complete",
              node: nodeName,
              label: NODE_LABELS[nodeName],
              data: output ?? {},
            });
          }
        }

        send({ type: "done" });
      } catch (err) {
        console.error("[/api/research] Stream error:", err);
        send({
          type: "error",
          message:
            err instanceof Error
              ? err.message
              : "An unexpected error occurred during research.",
        });
      } finally {
        controller.close();
      }
    },

    cancel() {
      // Client disconnected — nothing to clean up since we have no persistent state
    },
  });

  return new Response(stream, {
    headers: {
      "Content-Type": "text/event-stream",
      "Cache-Control": "no-cache, no-transform",
      Connection: "keep-alive",
      // Disables nginx/proxy buffering — ensures chunks reach the client immediately
      "X-Accel-Buffering": "no",
    },
  });
}

