/**
 * components/ConfidenceGauge.tsx
 *
 * SVG arc gauge showing confidence score 0-100.
 * No external chart library — pure SVG arc math.
 *
 * The gauge is a semicircle arc. 0 = empty (left end), 100 = full arc (right end).
 * Color: brass (#C9A227). Accessible via aria-label.
 */

"use client";

interface ConfidenceGaugeProps {
  score: number; // 0-100
  size?: number; // SVG viewBox size (default 120)
}

export function ConfidenceGauge({ score, size = 120 }: ConfidenceGaugeProps) {
  const clampedScore = Math.max(0, Math.min(100, score));

  // Arc geometry
  const cx = size / 2;
  const cy = size / 2;
  const r = (size / 2) * 0.75; // radius = 75% of half-size
  const strokeWidth = size * 0.1;

  // We draw a 270-degree arc (from 135° to 405°, i.e., 135° clockwise)
  const startAngle = 135; // degrees, measured from positive x-axis
  const totalSweep = 270; // degrees
  const fillSweep = (clampedScore / 100) * totalSweep;

  function polarToCartesian(
    cx: number,
    cy: number,
    r: number,
    angleDeg: number
  ) {
    const angleRad = ((angleDeg - 90) * Math.PI) / 180;
    return {
      x: cx + r * Math.cos(angleRad),
      y: cy + r * Math.sin(angleRad),
    };
  }

  function arcPath(
    cx: number,
    cy: number,
    r: number,
    startAngle: number,
    endAngle: number
  ) {
    const start = polarToCartesian(cx, cy, r, endAngle);
    const end = polarToCartesian(cx, cy, r, startAngle);
    const largeArc = endAngle - startAngle > 180 ? 1 : 0;
    return `M ${start.x} ${start.y} A ${r} ${r} 0 ${largeArc} 0 ${end.x} ${end.y}`;
  }

  const trackPath = arcPath(cx, cy, r, startAngle, startAngle + totalSweep);
  const fillPath =
    fillSweep > 0
      ? arcPath(cx, cy, r, startAngle, startAngle + fillSweep)
      : "";

  return (
    <div
      role="img"
      aria-label={`Confidence score: ${clampedScore} out of 100`}
      className="flex flex-col items-center gap-1"
    >
      <svg
        width={size}
        height={size * 0.75}
        viewBox={`0 0 ${size} ${size}`}
        style={{ overflow: "visible" }}
      >
        {/* Track */}
        <path
          d={trackPath}
          fill="none"
          stroke="#2A2E35"
          strokeWidth={strokeWidth}
          strokeLinecap="round"
        />
        {/* Fill */}
        {fillPath && (
          <path
            d={fillPath}
            fill="none"
            stroke="#C9A227"
            strokeWidth={strokeWidth}
            strokeLinecap="round"
            style={{ transition: "stroke-dasharray 0.5s ease" }}
          />
        )}
        {/* Score text */}
        <text
          x={cx}
          y={cy + 10}
          textAnchor="middle"
          fill="#C9A227"
          fontSize={size * 0.22}
          fontFamily="JetBrains Mono, monospace"
          fontWeight="600"
        >
          {clampedScore}
        </text>
        <text
          x={cx}
          y={cy + size * 0.28}
          textAnchor="middle"
          fill="#5B6470"
          fontSize={size * 0.1}
          fontFamily="Inter, sans-serif"
        >
          / 100
        </text>
      </svg>
      <span
        style={{
          fontFamily: "Inter, sans-serif",
          fontSize: "0.7rem",
          color: "#5B6470",
          textTransform: "uppercase",
          letterSpacing: "0.08em",
        }}
      >
        Confidence
      </span>
    </div>
  );
}

