/**
 * components/NodeCard.tsx
 *
 * Displays the status and output of a single pipeline node in the research feed.
 *
 * States:
 *   pending  — node is queued but hasn't started (dim, no content)
 *   loading  — node is currently running (pulse animation on dot)
 *   complete — node finished successfully (shows output data)
 *   error    — node produced an error (shows error message, keeps feed going)
 *
 * Typography rules applied:
 *   - Node label: Inter (sans)
 *   - Timestamps: JetBrains Mono (monospace)
 *   - Financial figures within content: monospace class applied inline
 *   - Section headings: Inter uppercase small caps
 */

"use client";

import { FundamentalsOutput, SentimentOutput, CompetitiveOutput } from "@/lib/agent/schemas";

export type NodeStatus = "pending" | "loading" | "complete" | "error";

export interface NodeCardData {
  node: string;
  label: string;
  status: NodeStatus;
  completedAt?: Date;
  data?: Record<string, unknown>;
  error?: string;
}

interface NodeCardProps {
  card: NodeCardData;
}

// Map node names to display configuration
const NODE_CONFIG: Record<string, { icon: string; section: string }> = {
  resolve_ticker:     { icon: "⬡", section: "Setup" },
  fetch_financials:   { icon: "⬡", section: "Data collection" },
  fetch_news:         { icon: "⬡", section: "Data collection" },
  fetch_web_research: { icon: "⬡", section: "Data collection" },
  gather_data:        { icon: "⬡", section: "Data collection" },
  analyze_fundamentals:  { icon: "⬡", section: "Analysis" },
  analyze_sentiment:     { icon: "⬡", section: "Analysis" },
  analyze_competitive:   { icon: "⬡", section: "Analysis" },
  synthesize_decision:   { icon: "⬡", section: "Synthesis" },
};

export function NodeCard({ card }: NodeCardProps) {
  const config = NODE_CONFIG[card.node] ?? { icon: "⬡", section: "Processing" };
  const isPending = card.status === "pending";
  const isLoading = card.status === "loading";
  const isComplete = card.status === "complete";
  const isError = card.status === "error";

  const statusDotColor = isComplete
    ? "#1A5F3F"
    : isError
    ? "#8B2635"
    : isLoading
    ? "#C9A227"
    : "#2A2E35";

  return (
    <div
      style={{
        borderBottom: "1px solid #1E2530",
        padding: "1.25rem 0",
        opacity: isPending ? 0.45 : 1,
        transition: "opacity 0.3s ease",
        animation: !isPending ? "slide-in 0.3s ease-out forwards" : "none",
      }}
    >
      {/* Header row */}
      <div
        style={{
          display: "flex",
          alignItems: "center",
          gap: "0.75rem",
          marginBottom: isComplete && card.data ? "1rem" : 0,
        }}
      >
        {/* Status dot */}
        <div
          style={{
            width: "8px",
            height: "8px",
            borderRadius: "50%",
            background: statusDotColor,
            flexShrink: 0,
            animation: isLoading ? "pulse 1.5s ease-in-out infinite" : "none",
          }}
        />

        {/* Label */}
        <span
          style={{
            fontFamily: "Inter, sans-serif",
            fontSize: "0.875rem",
            fontWeight: 500,
            color: isPending ? "#5B6470" : "#D4CFC8",
            flex: 1,
          }}
        >
          {card.label}
        </span>

        {/* Status text + timestamp */}
        <div style={{ display: "flex", alignItems: "center", gap: "0.75rem" }}>
          {isLoading && (
            <span
              style={{
                fontFamily: "Inter, sans-serif",
                fontSize: "0.72rem",
                color: "#C9A227",
                textTransform: "uppercase",
                letterSpacing: "0.08em",
              }}
            >
              Running
            </span>
          )}
          {isError && (
            <span
              style={{
                fontFamily: "Inter, sans-serif",
                fontSize: "0.72rem",
                color: "#8B2635",
                textTransform: "uppercase",
                letterSpacing: "0.08em",
              }}
            >
              Error
            </span>
          )}
          {card.completedAt && (
            <span
              style={{
                fontFamily: "JetBrains Mono, monospace",
                fontSize: "0.7rem",
                color: "#3A4048",
              }}
            >
              {card.completedAt.toLocaleTimeString("en-US", {
                hour: "2-digit",
                minute: "2-digit",
                second: "2-digit",
                hour12: false,
              })}
            </span>
          )}
        </div>
      </div>

      {/* Error message */}
      {isError && card.error && (
        <div
          style={{
            marginTop: "0.75rem",
            marginLeft: "1.4rem",
            padding: "0.6rem 0.875rem",
            background: "rgba(139,38,53,0.08)",
            borderLeft: "2px solid #8B2635",
            fontFamily: "Inter, sans-serif",
            fontSize: "0.8rem",
            color: "#B87070",
            lineHeight: 1.6,
          }}
        >
          {card.error}
        </div>
      )}

      {/* Node output content — rendered per node type */}
      {isComplete && card.data && (
        <div style={{ marginLeft: "1.4rem" }}>
          <NodeContent node={card.node} data={card.data} />
        </div>
      )}
    </div>
  );
}

// ---------------------------------------------------------------------------
// Node-specific content renderers
// ---------------------------------------------------------------------------

function NodeContent({
  node,
  data,
}: {
  node: string;
  data: Record<string, unknown>;
}) {
  switch (node) {
    case "resolve_ticker":
      return <ResolveTickerContent data={data} />;
    case "fetch_financials":
      return <FetchFinancialsContent data={data} />;
    case "fetch_news":
      return <FetchNewsContent data={data} />;
    case "fetch_web_research":
      return <FetchWebContent data={data} />;
    case "gather_data":
      return null; // Pass-through node — nothing to show
    case "analyze_fundamentals":
      return <FundamentalsContent data={data as unknown as FundamentalsOutput} />;
    case "analyze_sentiment":
      return <SentimentContent data={data as unknown as SentimentOutput} />;
    case "analyze_competitive":
      return <CompetitiveContent data={data as unknown as CompetitiveOutput} />;
    default:
      return null;
  }
}

// Resolve ticker output
function ResolveTickerContent({ data }: { data: Record<string, unknown> }) {
  const ticker = data.ticker as string | undefined;
  const profile = data.companyProfile as Record<string, unknown> | undefined;

  if (!ticker) return null;

  return (
    <div style={{ display: "flex", flexDirection: "column", gap: "0.3rem" }}>
      <div style={{ display: "flex", gap: "0.75rem", alignItems: "baseline" }}>
        <span style={monoStyle}>{ticker}</span>
        {profile?.name && (
          <span style={{ ...labelStyle, color: "#B8B3AC" }}>
            {profile.name as string}
          </span>
        )}
      </div>
      {profile && (
        <span style={metaStyle}>
          {[profile.sector, profile.industry, profile.exchange]
            .filter(Boolean)
            .join(" · ")}
        </span>
      )}
    </div>
  );
}

// Fetch financials output
function FetchFinancialsContent({ data }: { data: Record<string, unknown> }) {
  const available = data.financialsAvailable as boolean | undefined;
  if (available === false) {
    return (
      <span style={metaStyle}>No financial data available for this company.</span>
    );
  }
  const financials = data.financials as Record<string, unknown> | undefined;
  const stmts = (financials?.incomeStatements as unknown[]) ?? [];
  return (
    <span style={metaStyle}>
      {stmts.length} year{stmts.length !== 1 ? "s" : ""} of financial data retrieved
    </span>
  );
}

// Fetch news output
function FetchNewsContent({ data }: { data: Record<string, unknown> }) {
  const results = data.newsResults as unknown[] | undefined;
  const count = results?.length ?? 0;
  return (
    <span style={metaStyle}>
      {count} article{count !== 1 ? "s" : ""} retrieved
    </span>
  );
}

// Fetch web research output
function FetchWebContent({ data }: { data: Record<string, unknown> }) {
  const results = data.webResearchResults as unknown[] | undefined;
  const count = results?.length ?? 0;
  return (
    <span style={metaStyle}>
      {count} source{count !== 1 ? "s" : ""} retrieved
    </span>
  );
}

// Fundamentals analysis output
function FundamentalsContent({ data }: { data: FundamentalsOutput }) {
  const scoreColor =
    data.overallScore === "strong"
      ? "#1A5F3F"
      : data.overallScore === "weak"
      ? "#8B2635"
      : data.overallScore === "unavailable"
      ? "#5B6470"
      : "#C9A227";

  return (
    <div style={{ display: "flex", flexDirection: "column", gap: "0.75rem" }}>
      <div style={{ display: "flex", alignItems: "center", gap: "0.75rem" }}>
        <span
          style={{
            fontFamily: "Inter, sans-serif",
            fontSize: "0.7rem",
            textTransform: "uppercase",
