        >
          {data.overallScore}
        </span>
        {data.keyNumbers.length > 0 && (
          <div style={{ display: "flex", gap: "0.5rem", flexWrap: "wrap" }}>
            {data.keyNumbers.slice(0, 4).map((num, i) => (
              <span key={i} style={monoTagStyle}>
                {num}
              </span>
