/**
 * components/ResearchFeed.tsx
 *
 * Manages the SSE connection to the backend and renders the stream of nodes.
 *
 * Uses fetch() + ReadableStream reader to process SSE chunks because native
 * EventSource does not support POST requests.
 */

"use client";

import { useEffect, useState, useRef } from "react";
import { NodeCard, NodeCardData, NodeStatus } from "./NodeCard";
import { VerdictStamp } from "./VerdictStamp";
import { ErrorBanner } from "./ErrorBanner";
import { DecisionOutput } from "@/lib/agent/schemas";

// The ordered list of nodes expected in a full successful run
const EXPECTED_NODES = [
  "resolve_ticker",
  "fetch_financials",
  "fetch_news",
  "fetch_web_research",
  // gather_data is a pass-through, we don't need to display it as a card
  "analyze_fundamentals",
  "analyze_sentiment",
  "analyze_competitive",
  "synthesize_decision",
];

// Initial labels for pending states
const NODE_LABELS: Record<string, string> = {
  resolve_ticker: "Resolving ticker",
  fetch_financials: "Fetching financials",
  fetch_news: "Fetching news",
  fetch_web_research: "Researching competitive landscape",
  analyze_fundamentals: "Analyzing fundamentals",
  analyze_sentiment: "Analyzing sentiment",
  analyze_competitive: "Analyzing competitive position",
  synthesize_decision: "Synthesizing verdict",
};

interface ResearchFeedProps {
  companyName: string;
  onReset: () => void;
}

export function ResearchFeed({ companyName, onReset }: ResearchFeedProps) {
  // Initialize state with all expected nodes as pending
  const [nodes, setNodes] = useState<Record<string, NodeCardData>>(() => {
    const initial: Record<string, NodeCardData> = {};
    EXPECTED_NODES.forEach((node) => {
      initial[node] = {
        node,
        label: NODE_LABELS[node],
        status: "pending",
      };
    });
    return initial;
  });

  const [fatalError, setFatalError] = useState<string | null>(null);
  const [isDone, setIsDone] = useState(false);
  const [decision, setDecision] = useState<DecisionOutput | null>(null);
  const [resolvedTicker, setResolvedTicker] = useState<string | null>(null);

  // We use a ref to track if we've started fetching to prevent strict mode double-fetches
  const startedRef = useRef(false);

  useEffect(() => {
    if (startedRef.current) return;
    startedRef.current = true;

    const controller = new AbortController();

    async function startStream() {
      try {
        const res = await fetch("/api/research", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({ company: companyName }),
          signal: controller.signal,
        });

        if (!res.ok) {
          const errData = await res.json().catch(() => ({}));
          throw new Error(errData.error || `Server error: ${res.status}`);
        }

        if (!res.body) throw new Error("No response body");

        const reader = res.body.getReader();
        const decoder = new TextDecoder();
        let buffer = "";

        while (true) {
          const { done, value } = await reader.read();
          if (done) break;

          buffer += decoder.decode(value, { stream: true });
          const lines = buffer.split("\n\n");

          // Keep the last partial chunk in the buffer
          buffer = lines.pop() ?? "";

          for (const line of lines) {
            if (!line.startsWith("data: ")) continue;
            const dataStr = line.replace("data: ", "").trim();
            if (dataStr === "[DONE]") continue;

            try {
              const event = JSON.parse(dataStr);
              handleEvent(event);
            } catch (e) {
              console.warn("Failed to parse SSE event", dataStr, e);
            }
          }
        }
      } catch (err: any) {
        if (err.name === "AbortError") return;
        setFatalError(err.message || "Connection lost. Please try again.");
      }
    }

    startStream();

    return () => {
      controller.abort();
    };
  }, [companyName]);

  const handleEvent = (event: any) => {
    if (event.type === "node_start") {
      setNodes((prev) => ({
        ...prev,
        [event.node]: {
          ...prev[event.node],
          status: "loading",
          label: event.label || prev[event.node]?.label,
        },
      }));
    } else if (event.type === "node_complete") {
      setNodes((prev) => {
        const current = prev[event.node];
        // If the backend sent { errors: [...] } for this node
        const hasError = event.data?.errors && event.data.errors.length > 0;

        return {
          ...prev,
          [event.node]: {
            ...current,
            status: hasError ? "error" : "complete",
            data: event.data,
            error: hasError ? event.data.errors.join("; ") : undefined,
            completedAt: new Date(),
          },
        };
      });

      // Special extractions from specific nodes
      if (event.node === "resolve_ticker" && event.data?.ticker) {
        setResolvedTicker(event.data.ticker);
      } else if (event.node === "synthesize_decision" && event.data?.decision) {
        setDecision(event.data.decision);
      }
    } else if (event.type === "error") {
      setFatalError(event.message);
    } else if (event.type === "done") {
      setIsDone(true);
    }
  };

  return (
    <div style={{ maxWidth: "760px", margin: "0 auto", padding: "4rem 1.5rem" }}>
      <div style={{ marginBottom: "3rem", display: "flex", justifyContent: "space-between", alignItems: "baseline" }}>
        <h1
          style={{
            fontFamily: "Playfair Display, Georgia, serif",
            fontSize: "1.8rem",
            fontWeight: 600,
            color: "#F7F5F0",
            margin: 0,
          }}
        >
          Researching: {companyName}
        </h1>
        <button
          onClick={onReset}
          style={{
            background: "none",
            border: "none",
            color: "#8A939E",
            fontFamily: "Inter, sans-serif",
            fontSize: "0.875rem",
            cursor: "pointer",
            padding: 0,
          }}
        >
          Start over
        </button>
      </div>

      {fatalError && (
        <div style={{ marginBottom: "2rem" }}>
          <ErrorBanner message={fatalError} onRetry={onReset} />
        </div>
      )}

      <div style={{ display: "flex", flexDirection: "column" }}>
        {EXPECTED_NODES.map((nodeId) => {
          const card = nodes[nodeId];
          if (!card) return null;
          return <NodeCard key={nodeId} card={card} />;
        })}
      </div>

      {decision && (
        <div style={{ marginTop: "4rem" }}>
          <VerdictStamp
            decision={decision}
            companyName={companyName}
            ticker={resolvedTicker}
          />
        </div>
      )}

      {isDone && !decision && !fatalError && (
        <div style={{ marginTop: "2rem", padding: "1rem", color: "#8A939E", fontStyle: "italic" }}>
          Research pipeline finished without reaching a final verdict.
        </div>
      )}
    </div>
  );
}

"use client";

import { useState } from "react";
import { SearchForm } from "@/components/SearchForm";
import { ResearchFeed } from "@/components/ResearchFeed";

export default function Home() {
  const [targetCompany, setTargetCompany] = useState<string | null>(null);

  const handleSearchSubmit = (company: string) => {
    setTargetCompany(company);
  };

  const handleReset = () => {
    setTargetCompany(null);
  };

  return (
    <main style={{ minHeight: "100vh", backgroundColor: "#0B0E11" }}>
      {!targetCompany ? (
        <SearchForm onSubmit={handleSearchSubmit} isLoading={false} />
      ) : (
        <ResearchFeed companyName={targetCompany} onReset={handleReset} />
      )}
    </main>
  );
}

